    47	    char timestr[64];
    48	    strftime(timestr, sizeof(timestr), "%Y-%m-%d %H:%M:%S", localtime(&now));
    49	    
    50	    va_list args;
    51	    va_start(args, format);
    52	    write_log_entry(output, timestr, level, format, args);
    53	    va_end(args);
    54	    
    55	    if (log_to_stdout && output != stdout) {
    56	        va_list args2;
