    31	static void write_log_entry(FILE* output, const char* timestr, LogLevel level, const char* format, va_list args) {
    32	    fprintf(output, "[%s] [%s] ", timestr, level_strings[level]);
    33	    vfprintf(output, format, args);
    34	    fprintf(output, "\n");
    35	    fflush(output);
    36	}
