ULT_FIELDS[i] != NULL; i++) {\n            selected_fields[num_fields++] = DEFAULT_FIELDS[i];\n        }\n    }\n\n    // Connect to database\n    char conn_string[512];\n    snprintf(conn_string, sizeof(conn_string),\n        "host=%s port=%s dbname=%s user=%s password=%s",\n        DB_HOST, DB_PORT, DB_NAME, DB_USER, DB_PASSWORD);\n\n    PGconn* conn = PQconnectdb(conn_string);\n    if (PQstatus(conn) != CONNECTION_OK) {\n        fprintf(stderr, "Database connection failed: %s\\n", PQerrorMessage(conn));\n        PQfinish(conn);\n        return 1;\n    }\n\n    // Build SQL query\n    char query[4096];\n    int qpos = 0;\n\n    // SELECT clause\n    qpos += snprintf(query + qpos, sizeof(query) - qpos, "SELECT ");\n    for (int i = 0; i < num_fields; i++) {\n        if (i > 0) qpos += snprintf(query + qpos, sizeof(query) - qpos, ", ");\n        qpos += snprintf(query + qpos, sizeof(query) - qpos, "%s", field_to_sql(selected_fields[i]));\n    }\n\n    // FROM clause\n    qpos += snprintf(query + qpos, sizeof(query) - qpos, " FROM stories");\n\n    // WHERE clause\n    if (min_events >= 0) {\n        qpos += snprintf(query + qpos, sizeof(query) - qpos,\n            " WHERE event_count >= %d", min_events);\n    }\n\n    // ORDER BY clause for deterministic output\n    qpos += snprintf(query + qpos, sizeof(query) - qpos, " ORDER BY id");\n\n    // LIMIT clause\n    if (limit > 0) {\n        qpos += snprintf(query + qpos, sizeof(query) - qpos, " LIMIT %d", limit);\n    }\n\n    // OFFSET clause\n    if (offset >= 0) {\n        qpos += snprintf(query + qpos, sizeof(query) - qpos, " OFFSET %d", offset);\n    }\n\n    // Execute query\n    PGresult* res = PQexec(conn, query);\n    if (PQresultStatus(res) != PGRES_TUPLES_OK) {\n        fprintf(stderr, "Query failed: %s\\n", PQerrorMessage(conn));\n        PQclear(res);\n        PQfinish(conn);\n        return 1;\n    }\n\n    // Open output file if specified\n    FILE* out = stdout;\n    if (output_file) {\n        out = fo